struct Node {
    int data;
    struct Node* left;
    struct Node* right;
};

void inorderIterative(struct Node* root) {
    struct Node* stack[100];
    int top = -1;
    struct Node* curr = root;

    while (curr != NULL || top != -1) {
        // Push all left children onto stack
        while (curr != NULL) {
            stack[++top] = curr;
            curr = curr->left;
        }
        // Pop and visit node
        curr = stack[top--];
        printf("%d ", curr->data);
        // Move to right subtree
        curr = curr->right;
    }
}

from collections import deque

class TreeNode:
    def __init__(self, val):
        self.val = val
        self.left = None
        self.right = None

def levelOrder(root):
    if not root:
        return
    queue = deque([root])
    while queue:
        node = queue.popleft()
        print(node.val, end=' ')
        if node.left:
            queue.append(node.left)
        if node.right:
            queue.append(node.right)

